<script lang="ts">
	import { onMount } from 'svelte';
	import { page } from '$app/state';
	import { t } from '$i18n';
	import { siteConfig, shouldShowAds, getDownloadDomains } from '$lib/config';
	import AdSense from '$lib/components/AdSense.svelte';
	import Footer from '$lib/components/Footer.svelte';

	let { data } = $props<{ data: { lang: string; showAds: boolean } }>();
	let lang = data.lang;
	let showAds = $state(data.showAds);

	const DLC = siteConfig.download;

	// ─── stages ──────────────────────────────────────────────────
	type Stage = 'idle' | 'no-path' | 'fetching-ip' | 'checking-cache' | 'testing' | 'success' | 'fallback';
	let stage = $state<Stage>('idle');
	let progress = $state(0);
	let progressText = $state('');
	let errorMsg = $state('');
	let debugInfo = $state<string[]>([]);
	let bestDomain = $state('');
	let bestTime = $state(0);
	let scriptPath = $state('');

	function updateProgress(pct: number, text: string) {
		progress = pct;
		progressText = text;
	}

	function getScriptPath(): string | null {
		if (DLC.useQueryString) {
			const p = new URLSearchParams(window.location.search).get('path');
			return p ? p.replace(/^\/+/, '') : null;
		}
		const hash = window.location.hash;
		return (hash && hash.startsWith('#/')) ? decodeURIComponent(hash.substring(2)) : null;
	}

	async function fetchIP(): Promise<string> {
		const ctrl = new AbortController();
		const timeout = setTimeout(() => ctrl.abort(), DLC.ipTimeout);
		try {
			const r = await fetch('https://api.ipify.org?format=text', { signal: ctrl.signal });
			return (await r.text()).trim();
		} catch {
			return '0.0.0.0';
		} finally { clearTimeout(timeout); }
	}

	function cacheKey(ip: string): string { return `${DLC.cacheKey}_${ip}`; }

	function getCached(ip: string): { domain: string; time: number } | null {
		const raw = localStorage.getItem(cacheKey(ip));
		if (!raw) return null;
		try {
			const v = JSON.parse(raw);
			if (Date.now() - v.ts < DLC.cacheDays * 86400000) return { domain: v.domain, time: v.time };
		} catch {}
		return null;
	}

	function setCached(ip: string, domain: string, time: number) {
		localStorage.setItem(cacheKey(ip), JSON.stringify({ domain, time, ts: Date.now() }));
	}

	function testDomain(domain: string): Promise<number> {
		return new Promise((resolve) => {
			const start = performance.now();
			const iframe = document.createElement('iframe');
			iframe.style.display = 'none';
			iframe.src = `${domain}/gfork_speedtest.html?t=${Date.now()}`;
			const timer = setTimeout(() => { iframe.remove(); resolve(Infinity); }, DLC.testTimeout);
			const handler = (e: MessageEvent) => {
				if (e.data?.type === 'gfork_speedtest_pong') {
					clearTimeout(timer);
					iframe.remove();
					window.removeEventListener('message', handler);
					resolve(performance.now() - start);
				}
			};
			window.addEventListener('message', handler);
			document.body.appendChild(iframe);
		});
	}

	async function run() {
		const path = getScriptPath();
		if (!path) {
			errorMsg = '请在URL中添加脚本路径';
			stage = 'no-path';
			updateProgress(0, '等待路径');
			return;
		}
		scriptPath = path;

		stage = 'fetching-ip';
		updateProgress(10, '获取IP');
		const ip = await fetchIP();
		debugInfo = [`IP: ${ip}`];

		stage = 'checking-cache';
		updateProgress(20, '检查缓存');
		await new Promise(r => setTimeout(r, DLC.cacheTimeout));
		const cached = getCached(ip);
		if (cached) {
			debugInfo.push(`缓存命中: ${cached.domain} (${cached.time.toFixed(0)}ms)`);
			bestDomain = cached.domain;
			bestTime = cached.time;
			stage = 'success';
			updateProgress(100, '缓存命中');
			return;
		}
		debugInfo.push('无缓存, 开始测速');

		stage = 'testing';
		updateProgress(30, '开始测速');
		const domains = getDownloadDomains().slice(0, DLC.testCount);
		let best = { domain: '', time: Infinity };

		for (let i = 0; i < domains.length; i++) {
			updateProgress(30 + Math.floor((i / domains.length) * 50), `正在随机测试 ${domains.length} 个节点 (${i + 1}/${domains.length})`);
			const t = await testDomain(domains[i]!);
			debugInfo.push(`${domains[i]}: ${t === Infinity ? '超时' : t.toFixed(0) + 'ms'}`);
			if (t < best.time) { best = { domain: domains[i]!, time: t }; }
		}

		updateProgress(80, '分析结果中');
		if (!best.domain) {
			errorMsg = '所有节点测试失败, 取消下载';
			debugInfo.push('所有节点超时');
			stage = 'fallback';
			updateProgress(0, '失败');
			return;
		}

		bestDomain = best.domain;
		bestTime = best.time;
		setCached(ip, best.domain, best.time);
		stage = 'success';
		updateProgress(100, '完成');
	}

	function jumpToDownload() {
		if (!bestDomain || !scriptPath) return;
		window.location.href = `${bestDomain}/${scriptPath.replace(/^\//, '')}`;
	}

	let fallbackTimer: ReturnType<typeof setTimeout>;
	function startFallbackTimer() {
		if (fallbackTimer) clearTimeout(fallbackTimer);
		fallbackTimer = setTimeout(() => {
			if (stage === 'fallback' || stage === 'no-path') return;
			stage = 'fallback';
			errorMsg = '检测超时, 请稍后重试';
			updateProgress(0, '超时');
		}, DLC.autoFallbackMs);
	}

	onMount(() => {
		startFallbackTimer();
		run();
		return () => { if (fallbackTimer) clearTimeout(fallbackTimer); };
	});
</script>

<svelte:head>
	<title>{t(lang, 'download.title')} - {t(lang, 'site.name')}</title>
	<meta name="description" content={t(lang, 'download.description')} />
</svelte:head>

<section class="download-page">
	{#if shouldShowAds(lang)}
		<div class="content-wrapper" style="margin-bottom:16px">
			<AdSense slot={siteConfig.adsense.slots.generic} format="auto" />
		</div>
	{/if}

	<div class="content-wrapper">
		<div class="md3-card" id="download-app" style="min-height:400px;box-shadow:var(--md-sys-elevation-2)">
			<!-- idle: skeleton -->
			{#if stage === 'idle'}
				<div class="md3-skeleton" style="width:64px;height:64px;border-radius:50%;margin:0 auto 24px"></div>
				<div class="md3-skeleton" style="height:30px;width:180px;margin:0 auto 12px;border-radius:var(--md-sys-shape-corner-full)"></div>
				<div class="md3-skeleton" style="height:20px;width:260px;margin:0 auto 28px;border-radius:var(--md-sys-shape-corner-full)"></div>
				<div class="md3-skeleton" style="height:48px;margin:24px 0;border-radius:var(--md-sys-shape-corner-small)"></div>
				<div class="md3-skeleton" style="height:140px;margin:24px 0;border-radius:var(--md-sys-shape-corner-small)"></div>
			{/if}

			<!-- no-path -->
			{#if stage === 'no-path'}
				<div class="dl-icon"><span class="material-icons">link</span></div>
				<h1>脚本下载加速</h1>
				<p class="dl-desc">{errorMsg}</p>
				<div class="dl-tip">
					{DLC.useQueryString
						? '使用方式: 在URL后加上?path=your-script-path.user.js'
						: '使用方式: 在URL后加上#/your-script-path.user.js'}
				</div>
			{/if}

			<!-- fetching-ip / checking-cache -->
			{#if stage === 'fetching-ip' || stage === 'checking-cache'}
				<div class="dl-icon"><span class="material-icons">sync</span></div>
				<h1>脚本下载加速</h1>
				<p class="dl-desc">{progressText}</p>
				<div class="dl-progress-bar">
					<div class="dl-progress-fill" style="width:{progress}%"></div>
				</div>
			{/if}

			<!-- testing -->
			{#if stage === 'testing'}
				<div class="dl-icon"><span class="material-icons">speed</span></div>
				<h1>脚本下载加速</h1>
				<p class="dl-desc">{progressText}</p>
				<div class="dl-progress-bar">
					<div class="dl-progress-fill" style="width:{progress}%"></div>
				</div>
				{#if debugInfo.length > 0}
					<details class="dl-debug">
						<summary>提示: 正在随机测试 {getDownloadDomains().length} 个节点</summary>
						<pre>{debugInfo.join('\n')}</pre>
					</details>
				{/if}
			{/if}

			<!-- success -->
			{#if stage === 'success'}
				<div class="dl-icon"><span class="material-icons" style="color:var(--md-sys-color-primary)">check_circle</span></div>
				<h1>最快节点: {bestDomain.replace('https://', '')}</h1>
				<p class="dl-desc">响应时间: {bestTime.toFixed(0)}ms</p>
				<div class="dl-progress-bar">
					<div class="dl-progress-fill" style="width:100%;background:var(--md-sys-color-primary)"></div>
				</div>
				<div style="margin-top:24px;display:flex;gap:12px;justify-content:center;flex-wrap:wrap">
					<button class="md3-button md3-filled" onclick={jumpToDownload}>直接下载</button>
					<button class="md3-button md3-ripple" onclick={() => { stage = 'idle'; run(); }}>重新测速</button>
				</div>
				{#if debugInfo.length > 0}
					<details class="dl-debug" style="margin-top:16px">
						<summary>测试详情</summary>
						<pre>{debugInfo.join('\n')}</pre>
					</details>
				{/if}
			{/if}

			<!-- fallback -->
			{#if stage === 'fallback'}
				<div class="dl-icon"><span class="material-icons" style="color:var(--md-sys-color-error)">error</span></div>
				<h1>测速失败</h1>
				<p class="dl-desc">{errorMsg}</p>
				<div style="margin-top:24px;display:flex;gap:12px;justify-content:center;flex-wrap:wrap">
					<button class="md3-button md3-filled" onclick={() => { stage = 'idle'; run(); }}>重试</button>
					<a href="/{lang}" class="md3-button md3-ripple">回到首页</a>
				</div>
				{#if debugInfo.length > 0}
					<details class="dl-debug" style="margin-top:16px">
						<summary>诊断信息</summary>
						<pre>{debugInfo.join('\n')}</pre>
					</details>
				{/if}
			{/if}
		</div>
	</div>

	{#if shouldShowAds(lang)}
		<div class="content-wrapper" style="margin-top:16px">
			<AdSense slot={siteConfig.adsense.slots.generic} format="auto" />
		</div>
	{/if}
</section>

<Footer {lang} showAds={showAds} />

<style>
	.download-page { padding: 32px 0; }
	.content-wrapper { max-width: 720px; margin: 0 auto; padding: 0 16px; }
	#download-app { padding: 48px 32px; text-align: center; }
	.dl-icon { margin-bottom: 24px; }
	.dl-icon .material-icons { font-size: 64px; color: var(--md-sys-color-on-surface-variant); }
	#download-app h1 { font-family: var(--md-sys-typescale-headline-medium-font, inherit); font-size: 24px; font-weight: 600; margin: 0 0 12px; color: var(--md-sys-color-on-surface); }
	.dl-desc { font-size: 15px; color: var(--md-sys-color-on-surface-variant); margin: 0 0 20px; }
	.dl-tip { font-size: 13px; color: var(--md-sys-color-outline); background: var(--md-sys-color-surface-container); padding: 12px 16px; border-radius: var(--md-sys-shape-corner-small); margin-top: 12px; word-break: break-all; }
	.dl-progress-bar { width: 100%; max-width: 400px; height: 4px; background: var(--md-sys-color-surface-container-highest); border-radius: 2px; margin: 16px auto 0; overflow: hidden; }
	.dl-progress-fill { height: 100%; background: var(--md-sys-color-primary); border-radius: 2px; transition: width 0.3s ease; }
	.dl-debug { margin: 16px auto 0; max-width: 480px; text-align: left; font-size: 12px; }
	.dl-debug summary { cursor: pointer; color: var(--md-sys-color-on-surface-variant); padding: 8px; border-radius: var(--md-sys-shape-corner-small); }
	.dl-debug pre { background: var(--md-sys-color-surface-container); padding: 12px; border-radius: var(--md-sys-shape-corner-small); font-size: 11px; white-space: pre-wrap; word-break: break-all; color: var(--md-sys-color-on-surface-variant); margin: 8px 0 0; }
	@media (max-width: 600px) { #download-app { padding: 32px 16px; } }
</style>
